public int findTargetDistance(int[] nums, int target, int start) {
    int minDistance = Integer.MAX_VALUE;
    for(int i = 0; i < nums.length; i++) {
        if(nums[i] == target) {
            int distance = Math.abs(i - start);
            minDistance = Math.min(minDistance, distance);
        }
    }
    return minDistance;
}
```

